import React, { useMemo, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Input, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { bhService } from '../../../services/bh/bhService';
import type { OrderLineDto } from '../../../services/bh/models';
import { DocumentFormHeader } from '../../../components/layout';
import { OrderLinesGrid, useMaterialLinesSelection } from '../../../components/form';
import { CustomerSearchField } from '../../../components/search';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { customerFieldHandlers, loadCustomerDisplay } from '../../../utils/customerField';
import { emptyOrderLine, normalizeOrderLines, orderLinesTotal } from '../../../utils/orderLines';
import {
  SalesVoucherFormFooter,
  SalesVoucherFormShell,
  SalesVoucherHeaderSection,
  VoucherFormRow,
} from '../../../components/voucher';
import { useSalesFormProcessingLevel } from '../../../hooks/useSalesFormProcessingLevel';
import df from '../../../styles/documentForm.module.css';

const XuatHangFormPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const isEdit = Boolean(id);
  const isNew = !isEdit;
  const navigate = useNavigate();
  const dispatch = useAppDispatch();
  const initFormName = isEdit ? 'edit-sales-delivery' : 'create-sales-delivery';
  const { warehouseOptions } = useVoucherInitData(initFormName);
  const {
    processingLevel,
    setProcessingLevel,
    processingLevelOptions,
  } = useSalesFormProcessingLevel(initFormName);
  const whOpts = useMemo(
    () => [{ value: '', label: '— Chọn kho —' }, ...warehouseOptions],
    [warehouseOptions],
  );
  const [deliveryDate, setDeliveryDate] = useState(new Date().toISOString().slice(0, 10));
  const [customerId, setCustomerId] = useState('');
  const [customerCode, setCustomerCode] = useState('');
  const [customerName, setCustomerName] = useState('');
  const [warehouseId, setWarehouseId] = useState('');
  const [description, setDescription] = useState('');
  const [lines, setLines] = useState<OrderLineDto[]>([emptyOrderLine()]);
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);
  const [headerExpanded, setHeaderExpanded] = useState(true);

  const customerHandlers = useMemo(
    () => customerFieldHandlers(setCustomerId, setCustomerCode, setCustomerName),
    [],
  );
  const { copyLine, lineRowProps, setSelectedLineIndex } = useMaterialLinesSelection(lines, setLines);

  React.useEffect(() => {
    if (!id) return;
    let cancelled = false;
    const t = setTimeout(() => {
      bhService.getDelivery(id)
        .then(async d => {
          if (cancelled) return;
          setDeliveryDate(d.deliveryDate.slice(0, 10));
          setCustomerId(d.customerId);
          setWarehouseId(d.warehouseId);
          setDescription('');
          setLines(d.lines?.length ? d.lines : [emptyOrderLine()]);
          const display = await loadCustomerDisplay(d.customerId, d.customerName);
          if (!cancelled) {
            setCustomerCode(display.code);
            setCustomerName(display.name);
          }
        })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Lỗi tải phiếu xuất hàng'), type: 'error' });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, dispatch]);

  const addLine = () => {
    setLines(prev => [...prev, emptyOrderLine()]);
    setSelectedLineIndex(lines.length);
  };

  const removeLine = (idx: number) => {
    setLines(prev => {
      const next = prev.filter((_, i) => i !== idx);
      return next.length ? next : [emptyOrderLine()];
    });
    setSelectedLineIndex(Math.max(0, idx - 1));
  };

  const handleSave = async () => {
    if (!customerId || !warehouseId) {
      dispatchAppToast(dispatch, { message: 'Chọn khách hàng và kho', type: 'error' });
      return;
    }
    const normalized = normalizeOrderLines(lines);
    if (normalized.length === 0) {
      dispatchAppToast(dispatch, { message: 'Thêm ít nhất một dòng hàng', type: 'error' });
      return;
    }
    setSaving(true);
    try {
      const payload = {
        deliveryDate,
        customerId,
        warehouseId,
        description,
        lines: normalized,
      };
      if (isEdit && id) {
        await bhService.updateDelivery(id, payload);
        dispatchAppToast(dispatch, { message: 'Cập nhật phiếu xuất hàng thành công', type: 'success' });
      } else {
        await bhService.createDelivery(payload);
        dispatchAppToast(dispatch, { message: 'Tạo phiếu xuất hàng thành công', type: 'success' });
      }
      navigate('/bh/xuat-hang');
    } catch (err: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Lưu thất bại'), type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className={df.loading}>Đang tải...</div>;

  const total = orderLinesTotal(lines);

  return (
    <SalesVoucherFormShell
      testIdPrefix="xuat-hang"
      header={(
        <DocumentFormHeader
          onBack={() => navigate('/bh/xuat-hang')}
          title={isEdit ? 'Sửa phiếu xuất hàng' : 'Tạo phiếu xuất hàng'}
          isNew={isNew}
          saving={saving}
          saveLabel="Tạo phiếu"
          saveEditLabel="Lưu thay đổi"
          onSave={handleSave}
        />
      )}
      footer={(
        <SalesVoucherFormFooter
          testIdPrefix="xuat-hang"
          totals={[{ label: 'Tổng cộng:', amount: total }]}
          processingLevel={processingLevel}
          onProcessingLevelChange={setProcessingLevel}
          processingLevelOptions={processingLevelOptions}
          processingLevelDisabled={isEdit}
        />
      )}
    >
      <SalesVoucherHeaderSection
        title="Thông tin phiếu xuất"
        testIdPrefix="xuat-hang"
        headerExpanded={headerExpanded}
        setHeaderExpanded={setHeaderExpanded}
      >
        {({ fieldClass, compactHideClass, formRowStyles }) => (
          <VoucherFormRow styles={formRowStyles}>
            <div className={fieldClass(compactHideClass(true))}>
              <label className={df.label}>Ngày xuất</label>
              <Input type="date" value={deliveryDate} onChange={e => setDeliveryDate(e.target.value)} disabled={isEdit} />
            </div>
            <div className={fieldClass(df.spanCol2, compactHideClass(true))}>
              <label className={df.label}>Khách hàng</label>
              <CustomerSearchField
                customerId={customerId}
                customerCode={customerCode}
                customerName={customerName}
                onSelect={customerHandlers.onSelect}
                onClear={customerHandlers.onClear}
                disabled={isEdit}
                testIdPrefix="xuat-hang-customer"
              />
            </div>
            <div className={fieldClass(compactHideClass(false))}>
              <label className={df.label}>Kho</label>
              <Select value={warehouseId} onChange={e => setWarehouseId(e.target.value)} options={whOpts} />
            </div>
            <div className={fieldClass(compactHideClass(false))}>
              <label className={df.label}>Diễn giải</label>
              <Input value={description} onChange={e => setDescription(e.target.value)} />
            </div>
          </VoucherFormRow>
        )}
      </SalesVoucherHeaderSection>
      <div className={[df.section, df.linesSection].join(' ')}>
        <h2 className={df.sectionTitle}>Chi tiết hàng xuất</h2>
        <OrderLinesGrid
          lines={lines}
          canEdit
          onChange={setLines}
          onAddLine={addLine}
          onCopyLine={copyLine}
          lineRowProps={lineRowProps}
          onRemoveLine={removeLine}
        />
      </div>
    </SalesVoucherFormShell>
  );
};

export default XuatHangFormPage;

